package demo.reservation.repository;

import demo.reservation.model.entity.TemporaryPassword;
import demo.reservation.model.entity.UserEntity;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.stereotype.Repository;

import java.util.List;
import java.util.Optional;

@Repository
public interface TemporaryPasswordRepository extends JpaRepository<TemporaryPassword, Long> {

    List<TemporaryPassword> findAllByUserAndIsUsedFalse(UserEntity user);

    Optional<TemporaryPassword> findByIdAndUserAndIsUsedFalse(Long id, UserEntity user);

    long countByUserAndIsUsedFalse(UserEntity user);

    void deleteAllByUser(UserEntity user);
}

package demo.reservation.service;

import demo.reservation.model.AuthenticationRequest;
import demo.reservation.model.AuthenticationResponse;
import demo.reservation.model.UserRequestDto;
import demo.reservation.model.entity.UserEntity;
import demo.reservation.model.UserRole;
import demo.reservation.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

@Service
@RequiredArgsConstructor
public class AuthenticationService {

    private final UserRepository repository;
    private final PasswordEncoder passwordEncoder;
    private final JwtService jwtService;
    private final AuthenticationManager authenticationManager;


    public AuthenticationResponse register(UserRequestDto request) {
        var user = UserEntity.builder()
                .name(request.name())
                .email(request.email())
                .password(passwordEncoder.encode(request.password()))
                .role(UserRole.USER)
                .build();

        repository.save(user);

        var jwtToken = jwtService.generateToken(user);
        return AuthenticationResponse.builder()
                .token(jwtToken)
                .build();
    }


    public AuthenticationResponse authenticate(AuthenticationRequest request) {
        authenticationManager.authenticate(
                new UsernamePasswordAuthenticationToken(
                        request.email(),
                        request.password()
                )
        );

        var user = repository.findByEmail(request.email())
                .orElseThrow(() -> new RuntimeException("User not found after auth"));

        var jwtToken = jwtService.generateToken(user);
        return AuthenticationResponse.builder()
                .token(jwtToken)
                .build();
    }
}

package demo.reservation.service;

import demo.reservation.model.AuthenticationRequest;
import demo.reservation.model.AuthenticationResponse;
import demo.reservation.model.ResetPasswordWithTempDto;
import demo.reservation.model.UserRequestDto;
import demo.reservation.model.entity.UserEntity;
import demo.reservation.model.UserRole;
import demo.reservation.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.security.authentication.AuthenticationManager;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

@Service
@RequiredArgsConstructor
public class AuthenticationService {

    private final UserRepository repository;
    private final PasswordEncoder passwordEncoder;
    private final JwtService jwtService;
    private final AuthenticationManager authenticationManager;
    private final TemporaryPasswordService temporaryPasswordService;


    public AuthenticationResponse register(UserRequestDto request) {
        var user = UserEntity.builder()
                .name(request.name())
                .email(request.email())
                .password(passwordEncoder.encode(request.password()))
                .role(UserRole.USER)
                .build();

        repository.save(user);

        var jwtToken = jwtService.generateToken(user);
        return AuthenticationResponse.builder()
                .token(jwtToken)
                .build();
    }


    public AuthenticationResponse authenticate(AuthenticationRequest request) {
        authenticationManager.authenticate(
                new UsernamePasswordAuthenticationToken(
                        request.email(),
                        request.password()
                )
        );

        var user = repository.findByEmail(request.email())
                .orElseThrow(() -> new RuntimeException("User not found after auth"));

        var jwtToken = jwtService.generateToken(user);
        return AuthenticationResponse.builder()
                .token(jwtToken)
                .build();
    }

    /**
     * Сброс пароля с использованием временного пароля
     * @param request данные для сброса пароля
     * @return AuthenticationResponse с JWT токеном
     */
    public AuthenticationResponse resetPasswordWithTemporaryPassword(ResetPasswordWithTempDto request) {
        // Находим пользователя по ID
        var user = repository.findById(request.userId())
                .orElseThrow(() -> new RuntimeException("User not found"));

        // Проверяем временный пароль
        if (!temporaryPasswordService.validateAndUseTemporaryPassword(user, request.temporaryPassword())) {
            throw new RuntimeException("Invalid or expired temporary password");
        }

        // Обновляем основной пароль
        user.setPassword(passwordEncoder.encode(request.newPassword()));
        repository.save(user);

        // Генерируем новый JWT токен
        var jwtToken = jwtService.generateToken(user);
        return AuthenticationResponse.builder()
                .token(jwtToken)
                .build();
    }
}

package demo.reservation.service;

import demo.reservation.model.entity.TemporaryPassword;
import demo.reservation.model.entity.UserEntity;
import demo.reservation.repository.TemporaryPasswordRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;

@Service
@RequiredArgsConstructor
@Transactional
public class TemporaryPasswordService {

    private final TemporaryPasswordRepository repository;
    private final PasswordEncoder passwordEncoder;

    private static final int TEMP_PASSWORD_COUNT = 10;
    private static final int TEMP_PASSWORD_VALIDITY_HOURS = 24;

    /**
     * Генерирует 10 новых временных паролей для пользователя
     * Удаляет старые неиспользованные пароли
     * @param user пользователь
     * @return список сгенерированных временных паролей в открытом виде (только один раз)
     */
    public List<String> generateTemporaryPasswords(UserEntity user) {
        // Удаляем все старые неиспользованные пароли
        repository.deleteAllByUser(user);

        List<String> generatedPasswords = new ArrayList<>();
        LocalDateTime now = LocalDateTime.now();
        LocalDateTime expiresAt = now.plusHours(TEMP_PASSWORD_VALIDITY_HOURS);

        // Генерируем 10 временных паролей
        for (int i = 0; i < TEMP_PASSWORD_COUNT; i++) {
            String tempPassword = UUID.randomUUID().toString().replace("-", "");
            generatedPasswords.add(tempPassword);

            TemporaryPassword temp = TemporaryPassword.builder()
                    .user(user)
                    .hashedPassword(passwordEncoder.encode(tempPassword))
                    .isUsed(false)
                    .createdAt(now)
                    .expiresAt(expiresAt)
                    .build();

            repository.save(temp);
        }

        return generatedPasswords;
    }

    /**
     * Проверяет и использует временный пароль
     * @param user пользователь
     * @param tempPassword временный пароль
     * @return true если проверка успешна и пароль отмечен как использованный
     */
    public boolean validateAndUseTemporaryPassword(UserEntity user, String tempPassword) {
        List<TemporaryPassword> unusedPasswords = repository.findAllByUserAndIsUsedFalse(user);

        for (TemporaryPassword tp : unusedPasswords) {
            // Проверяем, что пароль не истек
            if (LocalDateTime.now().isAfter(tp.getExpiresAt())) {
                continue;
            }

            // Проверяем совпадение пароля
            if (passwordEncoder.matches(tempPassword, tp.getHashedPassword())) {
                tp.setIsUsed(true);
                repository.save(tp);
                return true;
            }
        }

        return false;
    }

    /**
     * Получает количество оставшихся неиспользованных временных паролей
     * @param user пользователь
     * @return количество неиспользованных паролей
     */
    @Transactional(readOnly = true)
    public long getUnusedPasswordsCount(UserEntity user) {
        return repository.countByUserAndIsUsedFalse(user);
    }

    /**
     * Получает список информации о неиспользованных временных паролях (без самих паролей)
     * @param user пользователь
     * @return список временных паролей
     */
    @Transactional(readOnly = true)
    public List<TemporaryPassword> getUnusedPasswords(UserEntity user) {
        return repository.findAllByUserAndIsUsedFalse(user);
    }
}
